public class MarketingCampaignScheduler {
    // Define the maximum budget and number of campaigns
    private static final int MAX_BUDGET = 1000;
    private static final int MAX_CAMPAIGNS = 5;

    // Campaigns with cost and return
    private static final Campaign[] CAMPAIGNS = {
        new Campaign(150, 200),
        new Campaign(200, 300),
        new Campaign(100, 150),
        new Campaign(120, 250),
        new Campaign(180, 350)
    };

    // Dynamic programming table
    private static final int[] dp = new int[MAX_BUDGET + 1];

    // Method to solve the problem
    public static void solve() {
        // Initialize the dp array
        for (int i = 0; i <= MAX_BUDGET; i++) {
            dp[i] = 0;
        }

        // Fill the dp array
        for (Campaign campaign : CAMPAIGNS) {
            for (int budget = MAX_BUDGET; budget >= campaign.cost; budget--) {
                if (dp[budget - campaign.cost] + campaign.returnValue > dp[budget]) {
                    dp[budget] = dp[budget - campaign.cost] + campaign.returnValue;
                }
            }
        }

        // Find the maximum return
        int maxReturn = dp[MAX_BUDGET];
        System.out.println("Maximum return: " + maxReturn);
    }

    // Campaign class
    static class Campaign {
        private final int cost;
        private final int returnValue;

        public Campaign(int cost, int returnValue) {
            this.cost = cost;
            this.returnValue = returnValue;
        }

        public int cost() {
            return cost;
        }

        public int returnValue() {
            return returnValue;
        }
    }

    // Main method
    public static void main(String[] args) {
        solve();
    }
}
