class WasteCollectionOptimizer {
private:
    vector<Location> locations;
    int numLocations;
    double truckCapacity;
    double fuelPerUnitDistance;

    // Distance between two locations
    double distanceBetween(const Location& loc1, const Location& loc2) {
        return sqrt((loc2.x - loc1.x) * (loc2.x - loc1.x) + (loc2.y - loc1.y) * (loc2.y - loc1.y));
    }

    // Dynamic programming table
    map<pair<int, int>, double> dp;

    // Memoized function to compute the minimum fuel cost for a route
    double minFuelCost(int start, int end) {
        // Check if we have already computed this state
        auto& state = dp[{start, end}];
        if (state != 0) return state;

        // Base case: if start == end, no fuel needed
        if (start == end) return 0.0;

        // Try all possible next locations
        double minCost = numeric_limits<double>::max();
        for (int i = 0; i < numLocations; ++i) {
            if (i == start) continue;
            double cost = distanceBetween(locations[start], locations[i]) + minFuelCost(i, end);
            if (cost < minCost) minCost = cost;
        }

        // Check if the truck can carry the load
        if (minCost > truckCapacity * fuelPerUnitDistance) {
            // If the path exceeds the capacity, skip it
            return numeric_limits<double>::max();
        }

        dp[{start, end}] = minCost;
        return minCost;
    }

public:
    WasteCollectionOptimizer(vector<Location> locs, double capacity, double fuelPerUnit) {
        locations = locs;
        numLocations = locs.size();
        truckCapacity = capacity;
        fuelPerUnitDistance = fuelPerUnit;
    }

    double optimizeRoute(int start, int end) {
        return minFuelCost(start, end);
    }
};

int main() {
    // Example garbage pickup locations
    vector<Location> locations = {
        {0, 0},
        {1, 1},
        {2, 0},
        {3, 3}
    };

    // Truck capacity and fuel per unit distance
    double truckCapacity = 10.0;
    double fuelPerUnit = 1.0;

    // Create optimizer
    WasteCollectionOptimizer optimizer(locations, truckCapacity, fuelPerUnit);

    // Optimize route from location 0 to location 3
    double result = optimizer.optimizeRoute(0, 3);
    cout << "Optimal fuel cost: " << result << endl;

    return 0;
}

