import java.util.*;

public class EmergencyEvacuation {
    // Class to represent a node in the graph
    static class Node {
        int id;
        int elevation;
        int waterLevel;
        Node[] neighbors;

        public Node(int id, int elevation, int waterLevel) {
            this.id = id;
            this.elevation = elevation;
            this.waterLevel = waterLevel;
            this.neighbors = new Node[0];
        }
    }

    // Class to represent a graph
    static class Graph {
        Node[] nodes;
        int numNodes;

        public Graph(int numNodes) {
            this.numNodes = numNodes;
            this.nodes = new Node[numNodes];
        }

        public void addNode(Node node) {
            nodes[numNodes++] = node;
        }

        public void addEdge(Node u, Node v, int weight) {
            u.neighbors = Arrays.copyOf(u.neighbors, u.neighbors.length + 1);
            u.neighbors[u.neighbors.length - 1] = v;
            v.neighbors = Arrays.copyOf(v.neighbors, v.neighbors.length + 1);
            v.neighbors[v.neighbors.length - 1] = u;
        }
    }

    // Dynamic programming approach to find the safest path
    public static List<Node> findSafePath(Graph graph, Node start, Node end) {
        int[][] dp = new int[graph.numNodes][graph.numNodes];
        int[] dist = new int[graph.numNodes];
        boolean[] visited = new boolean[graph.numNodes];

        // Initialize distances and visited array
        for (int i = 0; i < graph.numNodes; i++) {
            dist[i] = Integer.MAX_VALUE;
            visited[i] = false;
        }
        dist[start.id] = 0;
        visited[start.id] = true;

        // Dynamic programming loop
        for (int i = 0; i < graph.numNodes; i++) {
            int minDist = Integer.MAX_VALUE;
            int minIndex = -1;

            for (int j = 0; j < graph.numNodes; j++) {
                if (!visited[j] && dist[j] < minDist) {
                    minDist = dist[j];
                    minIndex = j;
                }
            }

            if (minIndex == -1) break;

            visited[minIndex] = true;

            for (Node neighbor : graph.nodes[minIndex].neighbors) {
                if (!visited[neighbor.id] && dist[neighbor.id] > dist[minIndex] + 1) {
                    dist[neighbor.id] = dist[minIndex] + 1;
                }
            }
        }

        // Reconstruct path
        List<Node> path = new ArrayList<>();
        int current = end.id;
        while (current != start.id) {
            path.add(graph.nodes[current]);
            current = dist[current] - 1;
        }
        path.add(graph.nodes[start.id]);

        // Backtrack from destination node
        for (int i = path.size() - 1; i > 0; i--) {
            Node currentNode = path.get(i);
            Node previousNode = path.get(i - 1);
            if (currentNode.id == previousNode.id) {
                break;
            }
        }

        return path;
    }

    public static void main(String[] args) {
        // Example usage
        int numNodes = 5;
        Graph graph = new Graph(numNodes);

        Node node1 = new Node(0, 100, 50);
        Node node2 = new Node(1, 80, 60);
        Node node3 = new Node(2, 90, 70);
        Node node4 = new Node(3, 70, 80);
        Node node5 = new Node(4, 110, 90);

        graph.addNode(node1);
        graph.addNode(node2);
        graph.addNode(node3);
        graph.addNode(node4);
        graph.addNode(node5);

        graph.addEdge(node1, node2, 1);
        graph.addEdge(node2, node3, 1);
        graph.addEdge(node3, node4, 1);
        graph.addEdge(node4, node5, 1);

        Node start = node1;
        Node end = node5;

        List<Node> safePath = findSafePath(graph, start, end);
        System.out.println("Safe path: " + safePath);
    }
}
