public class SuffixIndex {
    private Map<String, List<String>> suffixMap = new HashMap<>();

    public void addDocument(String title) {
        String[] suffixes = title.split("");
        for (int i = 0; i < suffixes.length; i++) {
            String suffix = new String(suffixes, i, suffixes.length - i);
            suffixMap.putIfAbsent(suffix, new ArrayList<>());
            suffixMap.get(suffix).add(title);
        }
    }

    public List<String> getRelevantDocuments(String query) {
        List<String> relevant = new ArrayList<>();
        String[] querySuffixes = query.split("");
        for (int i = 0; i < querySuffixes.length; i++) {
            String suffix = new String(querySuffixes, i, querySuffixes.length - i);
            List<String> docList = suffixMap.getOrDefault(suffix, new ArrayList<>());
            relevant.addAll(docList);
        }
        // Sort by relevance (lexicographic order if tied)
        relevant.sort(Comparator.comparing(String::compareTo));
        return relevant;
    }

    public static void main(String[] args) {
        SuffixIndex index = new SuffixIndex();
        index.addDocument("apple");
        index.addDocument("apples");
        index.addDocument("application");
        index.addDocument("app");

        String query1 = "app";
        String query2 = "apple";
        String query3 = "application";

        System.out.println("Query: " + query1 + " -> " + index.getRelevantDocuments(query1));
        System.out.println("Query: " + query2 + " -> " + index.getRelevantDocuments(query2));
        System.out.println("Query: " + query3 + " -> " + index.getRelevantDocuments(query3));
    }
