class Task {
public:
    std::string name;
    int priority;
    int executionTime;
    bool isCompleted = false;

    Task(const std::string& name, int priority, int executionTime) : name(name), priority(priority), executionTime(executionTime) {}
};

class TaskScheduler {
public:
    TaskScheduler() : taskQueue() {}

    void addTask(const std::string& name, int priority, int executionTime) {
        taskQueue.push(Task(name, priority, executionTime));
    }

    Task getNextTask() {
        if (taskQueue.empty()) {
            throw std::runtime_error("No tasks in the queue.");
        }
        return taskQueue.top();
    }

    void removeCompletedTasks() {
        while (!taskQueue.empty() && taskQueue.top().isCompleted) {
            taskQueue.pop();
        }
    }

    void executeTask() {
        if (taskQueue.empty()) {
            return;
        }
        Task task = taskQueue.top();
        task.isCompleted = true;
        std::cout << "Executing task: " << task.name << " (Priority: " << task.priority << ", Time: " << task.executionTime << ")\n";
        taskQueue.pop();
    }

private:
    std::priority_queue<Task, std::vector<Task>, std::greater<Task>> taskQueue;
};

int main() {
    TaskScheduler scheduler;

    // Add tasks
    scheduler.addTask("Email", 1, 30);
    scheduler.addTask("Meeting", 2, 45);
    scheduler.addTask("Report", 3, 60);

    // Execute tasks
    while (!scheduler.taskQueue.empty()) {
        scheduler.executeTask();
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_NODES 100

// Structure to represent a node in the graph
typedef struct Node {
    int id;
    struct Node* neighbors;
} Node;

// Structure to represent the graph
typedef struct Graph {
    int num_nodes;
    Node* nodes;
} Graph;

// Function to create a new node
Node* create_node(int id) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->id = id;
    node->neighbors = NULL;
    return node;
}

// Function to create a new graph
Graph* create_graph(int num_nodes) {
    Graph* graph = (Graph*)malloc(sizeof(Graph));
    graph->num_nodes = num_nodes;
    graph->nodes = (Node*)malloc(num_nodes * sizeof(Node));
    for (int i = 0; i < num_nodes; i++) {
        graph->nodes[i] = create_node(i);
    }
    return graph;
}

// Function to add an edge to the graph
void add_edge(Graph* graph, int u, int v) {
    Node* u_node = graph->nodes[u];
    Node* v_node = graph->nodes[v];
    u_node->neighbors = (Node*)realloc(u_node->neighbors, (u_node->neighbors ? u_node->neighbors->count + 1 : 1) * sizeof(Node));
    u_node->neighbors[u_node->neighbors->count++] = v_node;
    v_node->neighbors = (Node*)realloc(v_node->neighbors, (v_node->neighbors ? v_node->neighbors->count + 1 : 1) * sizeof(Node));
    v_node->neighbors[v_node->neighbors->count++] = u_node;
}

// Function to perform BFS
bool bfs(Graph* graph, int start, int target) {
    int visited[MAX_NODES];
    int queue[MAX_NODES];
    int front = 0, rear = 0;
    bool found = false;

    // Initialize visited array
    for (int i = 0; i < graph->num_nodes; i++) {
        visited[i] = 0;
    }
    visited[start] = 1;

    // Initialize queue
    queue[rear++] = start;

    while (front != rear) {
        int u = queue[front++];
        for (int i = 0; i < graph->nodes[u]->neighbors->count; i++) {
            int v = graph->nodes[u]->neighbors[i]->id;
            if (!visited[v]) {
                visited[v] = 1;
                queue[rear++] = v;
                if (v == target) {
                    found = true;
                    break;
                }
            }
        }
        if (found) break;
    }

    return found;
}

