    child->parent = parent;
    parent->children = child;
}

// Function to build the suffix tree
Node* buildSuffixTree(char* text) {
    int n = strlen(text);
    Node* root = createNode(text);
    Node* current = root;
    int i = 0;

    while (i < n) {
        Node* child = createNode(text + i);
        addNode(current, child);
        current->children = child;
        i++;
    }

    return root;
}

// Function to find all occurrences of a substring in the text
void findOccurrences(Node* root, char* substr) {
    int n = strlen(substr);
    int m = strlen(text);
    int i = 0;

    while (i < m) {
        Node* current = root;
        int j = 0;

        while (j < n && current->children && current->children[j]) {
            if (current->children[j]->data[0] == substr[j]) {
                current = current->children[j];
                j++;
            } else {
                break;
            }
        }

        if (j == n) {
            // Substring found at position i
            printf("Substring found at index %d\n", i);
            i += n;
        } else {
            i++;
        }
    }
}

int main() {
    char text[MAX_LEN];
    char substr[MAX_LEN];

    printf("Enter the text: ");
    fgets(text, MAX_LEN, stdin);
    text[strcspn(text, "\n")] = '\0';

    printf("Enter the substrings to search for: ");
    fgets(substr, MAX_LEN, stdin);
    substr[strcspn(substr, "\n")] = '\0';

    Node* root = buildSuffixTree(text);
    findOccurrences(root, substr);

    return 0;
}

