using namespace std;

struct Node {
    char data;
    int freq;
    Node* left;
    Node* right;
    Node(char ch, int f) : data(ch), freq(f), left(nullptr), right(nullptr) {}
};

Node* buildHuffmanTree(const string& input) {
    map<char, int> freqMap;
    for (char ch : input) {
        freqMap[ch] += 1;
    }

    priority_queue<Node*, vector<Node*>, decltype(&Node::freq)> maxHeap(freqMap.begin(), freqMap.end(), [](Node* a, Node* b) { return a->freq < b->freq; });

    while (maxHeap.size() > 1) {
        Node* left = maxHeap.top();
        maxHeap.pop();
        Node* right = maxHeap.top();
        maxHeap.pop();

        Node* newNode = new Node(' ', left->freq + right->freq);
        newNode->left = left;
        newNode->right = right;

        if (left->freq < right->freq) {
            left->right = newNode;
        } else {
            right->left = newNode;
        }

        maxHeap.push(newNode);
    }

    return maxHeap.top();
}

void encodeString(const string& input, Node* root, string& encodedString, map<char, string>& codeMap) {
    if (!root) return;

    if (root->data != ' ') {
        encodedString += root->data;
        codeMap[root->data] = encodedString;
    }

    encodeString(input, root->left, encodedString, codeMap);
    encodeString(input, root->right, encodedString, codeMap);
}

int main() {
    string input;
    cout << "Enter a string to compress: ";
    getline(cin, input);

    Node* root = buildHuffmanTree(input);

    map<char, string> codeMap;
    string encodedString = "";

    encodeString(input, root, encodedString, codeMap);

    cout << "Encoded string: " << encodedString << endl;

    cout << "Character to code mapping:" << endl;
    for (const auto& pair : codeMap) {
        cout << pair.first << " => " << pair.second << endl;
    }

    delete root;
    return 0;
}

