fn main() {
    let mut solutions = Vec::new();
    let mut board = vec![vec![0; 8]; 8];

    // Backtracking function
    fn backtrack(row: usize, col: usize, board: &mut Vec<Vec<usize>>, solutions: &mut Vec<Vec<usize>>) {
        if row == 8 {
            solutions.push(board.clone());
            return;
        }

        for col in 0..8 {
            if board[row][col] == 0 {
                // Check if the current position is valid
                if is_valid(board, row, col) {
                    board[row][col] = 1;
                    backtrack(row + 1, 0, board, solutions);
                    board[row][col] = 0;
                }
            }
        }
    }

    // Helper function to check if a position is valid
    fn is_valid(board: &Vec<Vec<usize>>, row: usize, col: usize) -> bool {
        for i in 0..row {
            if board[i][col] == 1 || 
               board[i][col] == 1 && 
               (i - row).abs() == (col - board[i][col]).abs() {
                return false;
            }
        }
        true
    }

    backtrack(0, 0, &mut board, &mut solutions);
    println!("Found {} solutions:", solutions.len());
    for solution in solutions {
        for row in 0..8 {
            for col in 0..8 {
                if solution[row][col] == 1 {
                    print!("Q ");
                } else {
                    print!("  ");
                }
            }
            println!();
        }
        println!();
    }
