using namespace std;

struct Task {
    int duration;
    int priority;
};

int main() {
    int timeLimit = 8 * 60 * 60; // 8 hours in seconds
    vector<Task> tasks = {
        {5, 3},
        {10, 5},
        {3, 2},
        {8, 4},
        {2, 1}
    };

    // Sort tasks by priority in descending order
    sort(tasks.begin(), tasks.end(), [](const Task& a, const Task& b) {
        return a.priority > b.priority;
    });

    // Dynamic programming table
    vector<vector<int>> dp(timeLimit + 1, vector<int>(tasks.size() + 1, 0));

    for (int i = 0; i < tasks.size(); ++i) {
        dp[0][i] = 0;
    }

    for (int t = 1; t <= timeLimit; ++t) {
        for (int i = 0; i < tasks.size(); ++i) {
            if (tasks[i].duration <= t) {
                dp[t][i + 1] = max(dp[t][i], dp[t - tasks[i].duration][i] + tasks[i].priority);
            }
        }
    }

    int maxPriority = 0;
    for (int i = 0; i <= timeLimit; ++i) {
        maxPriority = max(maxPriority, dp[i][tasks.size()]);
    }

    cout << "Optimized schedule: " << maxPriority << " priority score within 8 hours." << endl;
    return 0;
}

