use std::collections::{HashSet, VecDeque};

struct Edge {
    u: usize,
    v: usize,
    weight: u32,
}

struct Graph {
    adj: Vec<Vec<Edge>>,
    num_nodes: usize,
}

impl Graph {
    fn new(num_nodes: usize) -> Self {
        Graph {
            adj: vec![Vec::new(); num_nodes],
            num_nodes,
        }
    }

    fn add_edge(&mut self, u: usize, v: usize, weight: u32) {
        self.adj[u].push(Edge { u, v, weight });
        self.adj[v].push(Edge { v, u, weight });
    }

    fn prim(&self, start: usize) -> Vec<Edge> {
        let mut mst: Vec<Edge> = Vec::new();
        let mut visited: Vec<bool> = vec![false; self.num_nodes];
        let mut keys: Vec<u32> = vec![u32::MAX; self.num_nodes];

        keys[start] = 0;
        let mut queue = VecDeque::new();
        queue.push_back(start);

        while !queue.is_empty() {
            let u = queue.pop_front().unwrap();
            if visited[u] {
                continue;
            }
            visited[u] = true;

            for &(v, weight) in &self.adj[u] {
                if !visited[v] && weight < keys[v] {
                    keys[v] = weight;
                    queue.push_back(v);
                }
            }
        }

        // Collect edges in MST
        for i in 0..self.num_nodes {
            if visited[i] {
                for &(j, weight) in &self.adj[i] {
                    if visited[j] && weight < keys[j] {
                        mst.push(Edge { u: i, v: j, weight });
                    }
                }
            }
        }

        mst
    }
}

fn main() {
    let edges = vec![
        (0, 1, 5), (0, 2, 10), (1, 2, 15), (0, 3, 1), (3, 4, 6), (4, 5, 7),
        (5, 6, 8), (6, 7, 9), (7, 8, 10), (8, 9, 11), (9, 10, 12),
    ];

    let mut graph = Graph::new(11);
    for (u, v, w) in edges {
        graph.add_edge(u, v, w);
    }

    let mst = graph.prim(0);
    println!("Minimum Spanning Tree edges:");
    for edge in mst {
        println!("{}-{} with weight {}", edge.u, edge.v, edge.weight);
    }
}
