class BloomFilter {
    constructor(size, falsePositiveRate) {
        this.size = size;
        this.falsePositiveRate = falsePositiveRate;
        this.bitArray = new Array(size).fill(0);
    }

    add(item) {
        const index = this.hash(item);
        for (let i = 0; i < this.bitArray.length; i++) {
            this.bitArray[i] = (this.bitArray[i] + 1) % 2;
        }
    }

    check(item) {
        const index = this.hash(item);
        for (let i = 0; i < this.bitArray.length; i++) {
            if (this.bitArray[i] === 0) {
                return false;
            }
        }
        return true;
    }

    hash(item) {
        let hash = 0;
        for (let i = 0; i < item.length; i++) {
            hash = (hash + item.charCodeAt(i)) % this.size;
        }
        return hash % this.size;
    }
}

