#define INF INT_MAX

// Structure to represent a graph
typedef struct {
    int num_vertices;
    int num_edges;
    int **adjacency_list;
} Graph;

// Function to create a new graph
Graph* create_graph(int num_vertices, int num_edges) {
    Graph* graph = (Graph*)malloc(sizeof(Graph));
    graph->num_vertices = num_vertices;
    graph->num_edges = num_edges;
    graph->adjacency_list = (int**)malloc(num_edges * sizeof(int*));
    for (int i = 0; i < num_edges; i++) {
        graph->adjacency_list[i] = (int*)malloc(3 * sizeof(int));
    }
    return graph;
}

// Function to add an edge to the graph
void add_edge(Graph* graph, int u, int v, int weight) {
    graph->adjacency_list[graph->num_edges][0] = u;
    graph->adjacency_list[graph->num_edges][1] = v;
    graph->adjacency_list[graph->num_edges][2] = weight;
    graph->num_edges++;
}

// Function to initialize distances
void initialize_distances(Graph* graph, int start_vertex, int* dist) {
    for (int i = 0; i < graph->num_vertices; i++) {
        dist[i] = INF;
    }
    dist[start_vertex] = 0;
}

// Function to relax edges
void relax_edges(Graph* graph, int start_vertex, int* dist) {
    for (int i = 0; i < graph->num_edges; i++) {
        int u = graph->adjacency_list[i][0];
        int v = graph->adjacency_list[i][1];
        int weight = graph->adjacency_list[i][2];
        if (dist[v] > dist[u] + weight) {
            dist[v] = dist[u] + weight;
        }
    }
}

// Function to detect negative weight cycles
void detect_negative_cycle(Graph* graph, int start_vertex, int* dist) {
    for (int i = 0; i < graph->num_vertices; i++) {
        for (int j = 0; j < graph->num_edges; j++) {
            int u = graph->adjacency_list[j][0];
            int v = graph->adjacency_list[j][1];
            int weight = graph->adjacency_list[j][2];
            if (dist[v] > dist[u] + weight) {
                // Negative weight cycle detected
                printf("Negative weight cycle detected.\n");
                return;
            }
        }
    }
}

// Function to print the shortest distances
void print_distances(int* dist, int num_vertices) {
    for (int i = 0; i < num_vertices; i++) {
        printf("Distance from start to %d: %d\n", i, dist[i]);
    }
}

// Main function
int main() {
    int num_vertices, num_edges, start_vertex;
    printf("Enter number of vertices: ");
    scanf("%d", &num_vertices);
    printf("Enter number of edges: ");
    scanf("%d", &num_edges);
    printf("Enter starting vertex: ");
    scanf("%d", &start_vertex);

    // Validate starting vertex
    if (start_vertex < 0 || start_vertex >= num_vertices) {
        printf("Invalid starting vertex.\n");
        return 1;
    }

    // Create graph
    Graph* graph = create_graph(num_vertices, num_edges);
    for (int i = 0; i < num_edges; i++) {
        int u, v, weight;
        printf("Enter edge u v w: ");
        scanf("%d %d %d", &u, &v, &weight);
        add_edge(graph, u, v, weight);
    }

    // Initialize distances
    int* dist = (int*)malloc(num_vertices * sizeof(int));
    initialize_distances(graph, start_vertex, dist);

    // Relax edges
    relax_edges(graph, start_vertex, dist);

    // Detect negative weight cycles
    detect_negative_cycle(graph, start_vertex, dist);

    // Print distances
    print_distances(dist, num_vertices);

    free(dist);
    for (int i = 0; i < num_edges; i++) {
        free(graph->adjacency_list[i]);
    }
    free(graph->adjacency_list);
    free(graph);

    return 0;
}

