use std::collections::{HashSet, VecDeque};

fn kruskal_mst(edges: &[(&str, i32)], n: usize) -> Vec<&str> {
    // Sort edges by weight
    let mut sorted_edges = edges.to_vec();
    sorted_edges.sort_by(|a, b| a.1.cmp(&b.1));

    // Union-Find data structure
    let mut parent = vec![0; n];
    for i in 0..n {
        parent[i] = i;
    }

    let mut mst_edges = Vec::new();
    let mut edge_count = 0;

    // Process each edge
    for edge in sorted_edges {
        let (u, w) = (edge.0.parse::<usize>().unwrap(), edge.1);
        if find(parent, u) != find(parent, w) {
            union(parent, u, w);
            mst_edges.push(edge.0);
            edge_count += 1;
            if edge_count == n - 1 {
                break;
            }
        }
    }

    mst_edges
}

fn find(parent: &[usize], x: usize) -> usize {
    if parent[x] != x {
        parent[x] = find(parent, parent[x]);
    }
    parent[x]
}

fn union(parent: &mut [usize], x: usize, y: usize) {
    let x_root = find(parent, x);
    let y_root = find(parent, y);
    if x_root != y_root {
        parent[y_root] = x_root;
    }
}

