        ("A-B", 10),
        ("B-C", 15),
        ("A-C", 12),
        ("A-D", 10),
        ("D-E", 15),
        ("E-F", 10),
    ];
    let n = 6;
    let mst = kruskal_mst(&edges, n);
    println!("MST edges: {:?}", mst);
}
