import java.util.*;

public class UniversalHashTable {
    private static final double LOAD_FACTOR_THRESHOLD = 0.75;
    private static final int MAX_SIZE = 1000;
    private static final int[] HASH_PARAMETERS = {3, 7, 11, 13, 17, 19, 23, 29, 31};

    private final int[] table;
    private final int[] hashValues;
    private int size;

    public UniversalHashTable() {
        table = new int[MAX_SIZE];
        hashValues = new int[MAX_SIZE];
        size = 0;
    }

    public void insert(int key) {
        if (size >= MAX_SIZE) {
            throw new IllegalStateException("Hash table is full");
        }
        int index = hash(key);
        if (table[index] == 0) {
            table[index] = key;
            hashValues[index] = (int) (Math.random() * 1000);
            size++;
        } else {
            // Handle collision
            int[] newTable = new int[table.length * 2];
            int[] newHashValues = new int[table.length * 2];
            for (int i = 0; i < table.length; i++) {
                if (table[i] != 0) {
                    newTable[i] = table[i];
                    newHashValues[i] = hashValues[i];
                }
            }
            int newIndex = hash(key);
            newTable[newIndex] = key;
            newHashValues[newIndex] = (int) (Math.random() * 1000);
            size++;
            table = newTable;
            hashValues = newHashValues;
        }
    }

    private int hash(int key) {
        int hash = (int) (Math.random() * HASH_PARAMETERS.length);
        return hash;
    }

    public boolean delete(int key) {
        for (int i = 0; i < table.length; i++) {
            if (table[i] == key) {
                table[i] = 0;
                hashValues[i] = (int) (Math.random() * 1000);
                size--;
                return true;
            }
        }
        return false;
    }

    public boolean retrieve(int key) {
        for (int i = 0; i < table.length; i++) {
            if (table[i] == key) {
                return true;
            }
        }
        return false;
    }

    public void printStatistics() {
        System.out.println("Current size: " + size);
        System.out.println("Load factor: " + (size / (double) MAX_SIZE));
        System.out.println("Collision count: " + (table.length - size));
    }

    public static void main(String[] args) {
        UniversalHashTable hashTable = new UniversalHashTable();
        hashTable.insert(10);
        hashTable.insert(20);
        hashTable.insert(30);
        hashTable.insert(40);
        hashTable.insert(50);
        hashTable.insert(60);
        hashTable.insert(70);
        hashTable.insert(80);
        hashTable.insert(90);
        hashTable.insert(100);
        hashTable.printStatistics();
    }
}

