class BinaryTree {
  constructor(root) {
    this.root = root;
  }

  // Preprocess for Binary Lifting
  preprocess() {
    const maxDepth = this.getDepth(this.root);
    const logN = Math.floor(Math.log2(maxDepth)) + 1;
    const up = Array(maxDepth + 1).fill().map(() => Array(logN + 1).fill(null));

    function getDepth(node) {
      if (!node) return 0;
      return 1 + getDepth(node.left);
    }

    function setParent(node, parent) {
      node.parent = parent;
    }

    function setBinaryLifting(node, depth) {
      if (!node) return;
      up[depth][node] = node.parent;
      setBinaryLifting(node.left, depth + 1);
      setBinaryLifting(node.right, depth + 1);
    }

    setParent(this.root, null);
    setBinaryLifting(this.root, 0);
    return up;
  }

  getDepth(node) {
    if (!node) return 0;
    return 1 + this.getDepth(node.left);
  }

  findLCA(root, node1, node2) {
    if (!root || !node1 || !node2) return null;

    // Check if nodes exist
    if (!this.exists(root, node1) || !this.exists(root, node2)) return null;

    // Preprocess for Binary Lifting
    const up = this.preprocess();

    // Find LCA using Binary Lifting
    let lca = null;
    let depth1 = this.getDepth(node1);
    let depth2 = this.getDepth(node2);

    // Bring deeper node to same depth
    while (depth1 > depth2) {
      node1 = up[depth1][node1];
      depth1--;
    }
    while (depth2 > depth1) {
      node2 = up[depth2][node2];
      depth2--;
    }

    // If nodes are same, return it
    if (node1 === node2) return node1;

    // Move both up until they meet
    while (node1 !== node2) {
      node1 = up[1][node1];
      node2 = up[1][node2];
    }

    return node1;
  }

  exists(root, node) {
    if (!root) return false;
    if (root.value === node.value) return true;
    return this.exists(root.left, node) || this.exists(root.right, node);
  }
}

