void insertAtFront(Node** head, const string& title, const string& artist) {
    Node* newNode = createNode(title, artist);
    newNode->next = *head;
    if (*head != nullptr) {
        (*head)->prev = newNode;
    }
    *head = newNode;
}

// Function to insert a node at the end of the list
void insertAtEnd(Node** head, const string& title, const string& artist) {
    Node* newNode = createNode(title, artist);
    if (*head == nullptr) {
        *head = newNode;
        return;
    }
    Node* current = *head;
    while (current->next != nullptr) {
        current = current->next;
    }
    current->next = newNode;
    newNode->prev = current;
}

// Function to delete a node
void deleteNode(Node** head, Node* node) {
    if (node == *head) {
        if (node->next != nullptr) {
            node->next->prev = nullptr;
        }
        *head = node->next;
    } else {
        if (node->prev != nullptr) {
            node->prev->next = node->next;
        }
        if (node->next != nullptr) {
            node->next->prev = node->prev;
        }
    }
    delete node;
}

