    Node* nextNode = nullptr;
    Node* temp = nullptr;
    string title;

    // Extract all titles
    while (current != nullptr) {
        title = current->title;
        nextNode = current->next;
        // Sort using bubble sort
        while (nextNode != nullptr) {
            if (title > nextNode->title) {
                // Swap titles
                string tempTitle = title;
                title = nextNode->title;
                nextNode->title = tempTitle;
                // Swap artists
                string tempArtist = current->artist;
                current->artist = nextNode->artist;
                nextNode->artist = tempArtist;
                // Swap nodes
                Node* temp = current;
                current = nextNode;
                nextNode = temp;
            }
            nextNode = nextNode->next;
        }
        current = current->next;
    }
