use std::collections::HashMap;

struct DisjointSet {
    parent: HashMap<String, String>,
    rank: HashMap<String, usize>,
}

impl DisjointSet {
    fn new<T: ToString>(elements: &[T]) -> Self {
        let mut parent = HashMap::new();
        let mut rank = HashMap::new();
        for &element in elements {
            parent.insert(element.to_string(), element.to_string());
            rank.insert(element.to_string(), 0);
        }
        DisjointSet { parent, rank }
    }

    fn find<T: ToString>(&mut self, element: T) -> String {
        if let Some(parent) = self.parent.get_mut(&element) {
            if *parent == element {
                return element.to_string();
            }
            *parent = self.find(self.parent.get_mut(*parent).unwrap().clone());
        }
        *parent
    }

    fn union<T: ToString>(&mut self, element1: T, element2: T) -> bool {
        let root1 = self.find(element1);
        let root2 = self.find(element2);
        if root1 == root2 {
            return false;
        }
        if self.rank.get(&root1).unwrap() > self.rank.get(&root2).unwrap() {
            self.parent.insert(root2.clone(), root1.clone());
        } else {
            self.parent.insert(root1.clone(), root2.clone());
            if self.rank.get(&root1).unwrap() == self.rank.get(&root2).unwrap() {
                self.rank.insert(root2.clone(), self.rank.get(&root1).unwrap() + 1);
            }
        }
        true
    }
}
