using namespace std;

class Stack {
public:
    void push(int value) {
        stack.push(value);
    }

    int pop() {
        if (stack.empty()) {
            throw domain_error("Stack underflow");
        }
        int value = stack.top();
        stack.pop();
        return value;
    }

    bool isEmpty() {
        return stack.empty();
    }

    int size() {
        return stack.size();
    }
private:
    stack<int> stack;
};

bool isOperator(char ch) {
    return ch == '+' || ch == '-' || ch == '*' || ch == '/';
}

bool isValidPostfix(string expression) {
    Stack s;
    string tokens;
    istringstream iss(expression);
    string token;
    while (iss >> token) {
        if (isOperator(token[0])) {
            if (s.size() >= 2) {
                throw domain_error("Invalid postfix expression");
            }
            s.push(token[0]);
        } else {
            if (token.length() == 0) {
                throw domain_error("Invalid postfix expression");
            }
            s.push(token);
        }
    }
    return s.size() == 0;
}

int evaluatePostfix(string expression) {
    Stack s;
    istringstream iss(expression);
    string token;
    while (iss >> token) {
        if (isOperator(token[0])) {
            int b = s.pop();
            int a = s.pop();
            switch (token[0]) {
                case '+': s.push(a + b); break;
                case '-': s.push(a - b); break;
                case '*': s.push(a * b); break;
                case '/': s.push(a / b); break;
            }
        } else {
            s.push(token);
        }
    }
    return s.pop();
}

int main() {
    string expression;
    cout << "Enter postfix expression: ";
    getline(cin, expression);
    try {
        if (isValidPostfix(expression)) {
            int result = evaluatePostfix(expression);
            cout << "Result: " << result << endl;
        } else {
            cout << "Invalid postfix expression." << endl;
        }
    } catch (const domain_error& e) {
        cout << "Error: " << e.what() << endl;
    }
    return 0;
}

