public class DynamicOrderStatistics {
    private List<Integer> list;
    private int size;

    public DynamicOrderStatistics() {
        list = new ArrayList<>();
        size = 0;
    }

    public void add(int value) {
        list.add(value);
        size++;
        // Maintain order statistics
        Collections.sort(list);
    }

    public void remove(int value) {
        int index = list.indexOf(value);
        if (index != -1) {
            list.remove(index);
            size--;
            // Maintain order statistics
            Collections.sort(list);
        }
    }

    public double getMedian() {
        if (size % 2 == 1) {
            return (double) list.get(size / 2);
        } else {
            return (double) (list.get(size / 2 - 1) + list.get(size / 2)) / 2.0;
        }
    }

    public static void main(String[] args) {
        DynamicOrderStatistics ds = new DynamicOrderStatistics();
        ds.add(3);
        ds.add(1);
        ds.add(2);
        ds.add(4);
        System.out.println("Median after adding 3,1,2,4: " + ds.getMedian());
        ds.remove(1);
        System.out.println("Median after removing 1: " + ds.getMedian());
    }
}

