fn bellman_ford(graph: &Graph, source: Node) -> Option<Vec<isize>> {
    let num_nodes = graph.nodes.len();
    let mut dist = vec![-1; num_nodes];
    dist[source.id] = 0;

    for _ in 0..num_nodes {
        let mut updated = false;
        for edge in &graph.edges {
            let from = edge.from;
            let to = edge.to;
            if dist[from.id] != -1 && dist[to.id] > dist[from.id] + edge.weight {
                dist[to.id] = dist[from.id] + edge.weight;
                updated = true;
            }
        }
        if !updated {
            break;
        }
    }

    // Check for negative weight cycles
    for edge in &graph.edges {
        let from = edge.from;
        let to = edge.to;
        if dist[from.id] != -1 && dist[to.id] > dist[from.id] + edge.weight {
