// JavaScript program to model power grid construction using Prim's algorithm
class Graph {
  constructor() {
    this.adjacencyList = {};
  }

  addNode(node) {
    if (!this.adjacencyList[node]) {
      this.adjacencyList[node] = [];
    }
  }

  addEdge(node1, node2, weight) {
    this.addNode(node1);
    this.addNode(node2);
    this.adjacencyList[node1].push({ node2, weight });
    this.adjacencyList[node2].push({ node1, weight });
  }

  prim(start) {
    const visited = new Set();
    const minSpanningTree = [];

    const heap = new Heap();
    const startNode = this.adjacencyList[start];

    // Initialize heap with starting node
    for (const neighbor of startNode) {
      heap.heappush(heap, { weight: neighbor.weight, node: neighbor.node });
    }

    while (heap.length > 0) {
      const { weight, node } = heap.heappop(heap);
      if (visited.has(node)) continue;

      visited.add(node);
      minSpanningTree.push(weight);

      for (const neighbor of this.adjacencyList[node]) {
        if (!visited.has(neighbor.node) && neighbor.weight < Infinity) {
          heap.heappush(heap, { weight: neighbor.weight, node: neighbor.node });
        }
      }
    }

    return minSpanningTree;
  }
}

class Heap {
  constructor() {
    this.heap = [];
  }

  heappush(value) {
    this.heap.push(value);
    this._siftUp();
  }

  _siftUp() {
    let index = this.heap.length - 1;
    while (index > 0) {
      const parent = Math.floor((index - 1) / 2);
      if (this.heap[index].weight < this.heap[parent].weight) {
        [this.heap[index], this.heap[parent]] = [this.heap[parent], this.heap[index]];
        index = parent;
      } else {
        break;
      }
    }
  }

  heappop() {
    const popped = this.heap[0];
    this.heap[0] = this.heap.pop();
    this._siftDown();
    return popped;
  }

  _siftDown() {
    let index = 0;
    let maxIndex = index;

    while (true) {
      const left = 2 * index + 1;
      const right = 2 * index + 2;

      if (left < this.heap.length && this.heap[left].weight > this.heap[maxIndex].weight) {
        maxIndex = left;
      }

      if (right < this.heap.length && this.heap[right].weight > this.heap[maxIndex].weight) {
        maxIndex = right;
      }

      if (index === maxIndex) break;

      [this.heap[index], this.heap[maxIndex]] = [this.heap[maxIndex], this.heap[index]];
      index = maxIndex;
    }
  }
}

