def knapsack(weights, values, capacity):
    n = len(weights)
    dp = [[0] * (capacity + 1) for _ in range(n)]
    for i in range(n):
        for w in range(capacity + 1):
            if w >= weights[i]:
                dp[i][w] = max(dp[i-1][w], dp[i-1][w - weights[i]] + values[i])
            else:
                dp[i][w] = dp[i-1][w]
    return dp[n-1][capacity]

