int longestIncreasingSubsequence(const std::vector<int>& nums) {
    std::vector<int> dp;
    for (int num : nums) {
        auto it = std::lower_bound(dp.begin(), dp.end(), num);
        if (it != dp.end()) {
            *it = num;
        } else {
            dp.push_back(num);
        }
    }
    return dp.size();
}

