  { name: "Jumping Jacks", duration: 1, calories: 200 },
  { name: "Cycling", duration: 45, calories: 500 },
  { name: "Running", duration: 60, calories: 700 },
  { name: "Dumbbell Press", duration: 2, calories: 300 },
  { name: "Plank", duration: 30, calories: 450 }
];

// Function to calculate calorie burn-to-time ratio
function calculateRatio(exercise) {
  return exercise.calories / exercise.duration;
}

// Function to sort exercises by ratio (descending)
function sortExercisesByRatio(exercises) {
  return exercises.sort((a, b) => b.calories / b.duration - a.calories / a.duration);
}

// Function to generate weekly schedule
function generateWeeklySchedule(exercises, maxDuration) {
  const sortedExercises = sortExercisesByRatio(exercises);
  const schedule = [];

  for (let i = 0; i < 7; i++) {
    const currentExercise = sortedExercises.shift();
    if (currentExercise) {
      schedule.push({
        day: i + 1,
        exercise: currentExercise.name,
        duration: currentExercise.duration,
        calories: currentExercise.calories
      });
    }
  }

  return schedule;
}

// Main function to run the program
function main() {
  const maxDuration = 60; // 1 hour in minutes
  const weeklySchedule = generateWeeklySchedule(exercises, maxDuration);
  console.log("Weekly Fitness Plan:");
  weeklySchedule.forEach((item, index) => {
    console.log(`${index + 1}. Day ${item.day}: ${item.exercise} - ${item.duration} min, ${item.calories} calories`);
  });
}

