#include <iostream>
using namespace std;

int climbStairs(int n) {
    if (n == 0 || n == 1) return 1;
    int a = 1, b = 1;
    for (int i = 2; i <= n; ++i) {
        int c = a + b;
        a = b;
        b = c;
    }
    return b;
}

int main() {
    int n;
    cout << "Enter the number of steps: ";
    cin >> n;
    cout << "Unique ways to reach the top: " << climbStairs(n) << endl;
    return 0;
}
